-----------------------------------------------------------------
---搜索敌人， 并在地板左右巡逻
-----------------------------------------------------------------
---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdleSearchAction:LFightIdleBaseAction
local LFightIdleSearchAction = LxClass("LFightIdleSearchAction",LFightIdleBaseAction)
-----------------------------------------------------------------
LFightIdleSearchAction.PHASE_IDLE = 0 -- 0休息
LFightIdleSearchAction.PHASE_MOVE = 1 -- 1 行走

function LFightIdleSearchAction:LFightIdleSearchAction()
	self._action = LFightIdleConst.ACTION_SEARCH

	self._waitTime = 0

	self._phase = LFightIdleSearchAction.PHASE_IDLE -- 0 休息 1 行走,巡逻是由行走和休息构成

	self._nextScanTime = 0

	self._scanInterval = 0.2

	self._limitArea = nil
end

-----------------------------------------------------------------
function LFightIdleSearchAction:OnRun(time)
	if self._nextScanTime < time then
		if(self:DoScan()) then
			return
		end
	end

	if self._phase == LFightIdleSearchAction.PHASE_MOVE then
		local actor = self._obj:GetMoveActor()
		if not actor:IsMoving() then
			self:GoToWait()
		end
	elseif self._phase == LFightIdleSearchAction.PHASE_IDLE then
		if self._waitTime <= time then
			self:GotoPatrol()
		end
	end
end

function LFightIdleSearchAction:DoScan()
	self._nextScanTime = self:GetTime() + self._scanInterval

	local objCtr =self:GetObjCtrl()
	local teamList = objCtr:GetOppositeTeamBySide(self._obj:GetSide())
	local bHave = false
	local bNoEnemy = true
	for k,v in ipairs(teamList) do
		if v:IsLive() then
			bHave = true
			bNoEnemy = false
			break
		end
		if bNoEnemy and not v:IsDestroy() and not v:IsDead() then
			bNoEnemy = false
		end
	end
	if bHave then
		self._ai:ChangeAction(LFightIdleConst.ACTION_ATK)
		return true
	end

	return false
end

-----------------------------------------------------------------
function LFightIdleSearchAction:StartAction()
	self._nextCheckTime = 0
	self._phase = LFightIdleSearchAction.PHASE_IDLE

	self._stopAction = false

	self:CalcLimitArea()
end

function LFightIdleSearchAction:CircleArea()
	self:CalcLimitArea()
end
-----------------------------------------------------------------
function LFightIdleSearchAction:CalcLimitArea()
	if self._obj:GetObjType() == LFightIdleConst.OBJ_MON then
		local limitArea = self._obj:GetMonMoveArea()
		local birthPos = self._obj:GetBirthPos()
		local limitMin = birthPos.x + limitArea.min
		local limitMax = birthPos.x + limitArea.max
		self._limitArea = {min=limitMin,max=limitMax}
	end
end

-----------------------------------------------------------------
function LFightIdleSearchAction:GoToWait()
	self._phase = LFightIdleSearchAction.PHASE_IDLE
	if self._obj:GetObjType() == LFightIdleConst.OBJ_MON then
		local stayTimeLimit = self._obj:GetMonStayTime() or {}
		local min = stayTimeLimit.min or 0
		local max = stayTimeLimit.max or 0
		self._waitTime = self:GetTime() + math.random() * (max - min) + min
	else
		self._waitTime = self:GetTime() + math.random() * 1 + 0.5
	end

	self._obj:PlayIdleAni()
	self._obj:SetStatus(LFightIdleConst.STATUS_IDLE)
end
-----------------------------------------------------------------
function LFightIdleSearchAction:GotoPatrol()
	local obj = self._obj

	local pos = obj:GetPosition()
	local nowX = pos.x

	local minPos,maxPos = self._obj:GetPathData()

	local minX = minPos.x
	local maxX = maxPos.x

	local speed = obj:GetMoveSpeed()
	if obj:GetObjType() == LFightIdleConst.OBJ_MON then
		local speedRate = obj:GetMonMoveSpeedRate() or 1
		speed = speed * speedRate
		local limitArea = self._limitArea
		local limitMin = limitArea.min
		local limitMax = limitArea.max
		minX = Mathf.Max(limitMin,minX)
		maxX = Mathf.Min(limitMax,maxX)
	end

	local dir = obj:GetDirection()

	local targetX = 0
	--靠近左边 朝右边行走
	if LFightIdleConst.Approximately(nowX,minX) then
		targetX = maxX
		--靠近右边，朝左边行走
	elseif LFightIdleConst.Approximately(nowX,maxX) then
		targetX = minX
	else
		--朝远的点行走
		if Mathf.Abs(maxX - nowX) < Mathf.Abs(minX - nowX) then
			targetX = minX
		else
			targetX = maxX
		end
	end

	local actor = obj:GetMoveActor()

	local time = Mathf.Abs(targetX - nowX) / speed * 100

	local tarPos = Vector3(targetX,pos.y,pos.z)
	actor:MoveTo(tarPos,time)

	obj:SetStatus(LFightIdleConst.STATUS_MOVE)
	obj:PlayRunAni()

	obj:ChangeDirToPos(tarPos)

	self._phase = LFightIdleSearchAction.PHASE_MOVE
end
-----------------------------------------------------------------

function LFightIdleSearchAction:StopAction()
	self._stopAction = true
end

function LFightIdleSearchAction:Destroy()

	LFightIdleBaseAction.Destroy(self)
end


return LFightIdleSearchAction